import React, { Component } from 'react'
import {Link} from 'react-router-dom'
import './CardsComponent.css'

export default class CardsComponent extends Component {
    constructor(props){
        super(props);
        this.state={
            value:this.props.item,
        }
    }
    render(){
        const value=this.state.value;
        const {
            natureTitle,
            natureLocation,
            natureCoordination,
            imgBanner,
            imgBannerBg,
        } = value;
        let coordinat='';
        if(!!natureCoordination){
            coordinat='Координаты: '+natureCoordination;
        }
        localStorage.removeItem('cardData')
        const location={
            pathname: '/natureinfo',
            state: { data: value }
        }
        return (
                <div className="flip-card-container">
                    <div className="flip-card">
                        <div className="card-front">
                            <figure>
                                <div className="img-bg"></div>
                                <img className="card-image" loading='lazy' src={imgBanner} alt={natureTitle}/>
                                <figcaption>{natureTitle}</figcaption>
                            </figure>
                            <ul className='card-component-ul'>
                                <li className='card-component-li'>Расположен: {natureLocation}</li>
                                <li className='card-component-li'>{coordinat}</li>
                            </ul>
                        </div>
                        
                        <div className="card-back">
                            <figure>
                                <div className="img-bg"></div>
                                <img className="card-image" src={imgBannerBg} alt="Brohm Lake"/>
                            </figure>
                            
                            <Link className="card-button" to={location}  >
                                Подробнее
                            </Link>
                            <div className="design-container">
                                <span className="design design--1"></span>
                                <span className="design design--2"></span>
                                <span className="design design--3"></span>
                                <span className="design design--4"></span>
                                <span className="design design--5"></span>
                                <span className="design design--6"></span>
                                <span className="design design--7"></span>
                                <span className="design design--8"></span>
                            </div>
                        </div>

                    </div>
                </div>
          );
    }
  
}
